DELETE FROM projects;
DELETE FROM testimonials;



UPDATE services SET short_description = 'On crée votre jardin de A à Z : préparation du terrain, gazon, plantations. Tout est fait sur mesure.', full_description = 'Vous partez d''un terrain vide ou d''un jardin qui ne vous plaît plus ? On s''en occupe. On prépare le sol, on pose le gazon, on plante ce qu''il faut et on installe les clôtures si besoin.', features = ARRAY['Étude de votre terrain sur place', 'Préparation du sol et nivellement', 'Pose de gazon en plaques ou semis', 'Plantations adaptées à votre sol', 'Suivi après plantation'] WHERE id = 'creation-jardins';
UPDATE services SET short_description = 'Terrasses en pierre, bois ou dalles, allées et bordures. On aménage vos extérieurs pour en profiter vraiment.', full_description = 'On pose des terrasses en travertin, en bois, en dalles béton — selon vos goûts et votre budget. On fait aussi les allées, les bordures, les marches.', features = ARRAY['Terrasses en pierre, bois ou dalles', 'Allées et bordures', 'Pose sur dalle stabilisée', 'Drainage intégré', 'Garantie décennale'] WHERE id = 'amenagement-terrasses';
UPDATE services SET short_description = 'Tonte, taille de haies, désherbage, nettoyage. On entretient votre jardin toute l''année.', full_description = 'Un jardin, ça s''entretient. On passe régulièrement pour tondre, tailler les haies, désherber les massifs et nettoyer. Contrat à l''année ou ponctuel.', features = ARRAY['Tonte régulière', 'Taille de haies et arbustes', 'Désherbage des massifs', 'Nettoyage saisonnier', 'Contrats à l''année possibles'] WHERE id = 'entretien-paysager';
UPDATE services SET short_description = 'Élagage, abattage, taille d''arbres et d''arbustes. On intervient en toute sécurité, même en hauteur.', full_description = 'Vos arbres sont trop hauts, mal en point, ou trop proches de la maison ? On intervient en grimpe ou avec nacelle pour élaguer, réduire ou abattre en toute sécurité.', features = ARRAY['Élagage en grimpe', 'Abattage sécurisé', 'Taille de réduction', 'Dessouchage et broyage', 'Évacuation des déchets verts'] WHERE id = 'elagage';
UPDATE services SET short_description = 'Clôtures composite, alu, bois, grillage, murets et portails. On ferme et on sécurise votre terrain.', full_description = 'On pose tous types de clôtures : panneaux composites, aluminium, bois, grillage rigide. On fait aussi les murets, les portails et les portillons.', features = ARRAY['Clôtures composite et aluminium', 'Grillage rigide', 'Murets et bordures', 'Portails et portillons', 'Fondations béton solides'] WHERE id = 'clotures-murets';
UPDATE services SET short_description = 'Installation d''arrosage automatique pour un jardin toujours vert sans y penser.', full_description = 'On installe des systèmes d''arrosage automatique adaptés à votre jardin. Aspersion, goutte-à-goutte, programmateur — tout est réglé pour arroser au bon moment.', features = ARRAY['Étude de votre terrain', 'Aspersion et goutte-à-goutte', 'Programmateur automatique', 'Réglage zone par zone', 'Économie d''eau'] WHERE id = 'arrosage-automatique';
